-- ============================================================
-- FleetWash OS - REAL ACCOUNT LIST (123 companies)
-- Extracted from your demo (fleetwash-demo-v3) into your live clients table.
--
-- HOW TO RUN:
--   1. Log into the app once (owner profile must exist).
--   2. Supabase -> SQL Editor -> paste this whole file -> RUN.
--   3. Refresh the app -> Accounts tab shows all 123 companies.
--
-- Safe guard: refuses to run if you already have clients, so it
-- cannot create duplicates. To reload, clear clients first.
-- ============================================================

do $$
declare
  v_company uuid;
begin
  select company_id into v_company from profiles where role = 'owner' order by created_at limit 1;
  if v_company is null then
    raise exception 'No owner profile found. Log into the app once, then re-run.';
  end if;
  if (select count(*) from clients where company_id = v_company) > 0 then
    raise exception 'This company already has clients. Clear them before reloading to avoid duplicates.';
  end if;

  insert into clients
    (company_id, name, contact, phone, address, terms, arrival, frequency,
     fleet_notes, specialty, complaints, wash_time, washers, chems, requires_training, kind)
  values
    (v_company, 'A1 Movers', '', '', '704 Banks Ave, Superior, WI 54880', 'Net 30', '', '', 'Varies — tractors, trailers, straight trucks', '', '', '', '', '[]'::jsonb, false, 'client'),
    (v_company, 'Adamich Trucking', '', '', '4202 W Superior St., Duluth, MN', 'Net 30', 'Friday after 4pm', 'Biweekly', '1 tow truck', 'Parks in S&J Truck Repair lot', 'EXTREMELY PICKY!!!', '20 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Agiliti', '', '', '367 Garfield Ave, Duluth, MN 55802', 'Net 30', 'Sunday morning / around Cintas', 'Monthly', '1 box truck, 1 large cargo van', 'Don''t need to wash the smaller cargo van', '', '20 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Airgas - Duluth', '', '', '3102 W Michigan St, Duluth MN', 'Net 30', 'After 3:00 pm on Fridays', 'Bi-weekly', '3 box trucks, 1 cargo van', 'You need a gate key to get into Airgas (garage door opener that opens their gate). They often back up right to the dock but still want the backs done well — maneuver your vehicle to reach these. Usually easiest at the end on the way out.', 'Backs of trucks that are only accessible if you walk up on the dock', '45 min', '2 (need 1)', '[]'::jsonb, false, 'client'),
    (v_company, 'Airgas Hibbing', '', '', '3410 E Beltline Hwy, Hibbing, MN 55746', 'Net 30', '2:00 pm Sundays', 'Bi-weekly', '2-3 box trucks', 'Use the key to enter', 'N/A', '30 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Al Capone Limousine', '', '', '6420 Redruth St', 'Net 30', 'Random', 'As needed (they call)', 'Party buses & limos — no set number ever', 'Kind of weird to get to', 'Very picky! Use lots of water. Windows are biggest overall complaint. Leftover chem trails on vehicle.', 'Random', 'Usually 1', '[]'::jsonb, false, 'client'),
    (v_company, 'Altec', '', '', 'Heritage Center', 'Net 30', 'Random', '', 'Typically 1 aerial boom lift', '', '', '20 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'ATDS', 'Gary', '', '785 Louise Ln NW, Bemidji, MN 56601', 'Net 30', 'Saturdays', 'Weekly', '2-4 tractors, 2-4 trailers', 'They''ll cycle units through the shop so you can wash inside. Knock on shop door and find Gary — you can pull our truck in the shop and he''ll pull trucks in to get washed.', '', '120 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Barr Engineering Duluth', 'Don', '(218) 391-5025', '4503 Airpark Blvd, Duluth MN', 'Net 30', '1:00 pm on Tuesdays', 'Bi-weekly', '5-12 pickup trucks that say Barr on them', 'Call Don 20 minutes before you arrive. Unit numbers are long and in a yellow box generally.', 'Mudflaps, tires, windows', '40 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Beaudry Oil & Propane Bemidji', '', '', '1981 Adams Ave NW, Bemidji, MN 56601', 'Net 30', 'Weekends', 'Biweekly', '2 fuel trucks, 1 boom truck', 'Undercarriages every other service', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Beaudry Oil & Propane Coleraine', '', '', '803 Cole St., Coleraine, MN', 'Net 30', 'Weekends', 'Biweekly', '3 fuel trucks, 1 service truck', 'Undercarriages every other service', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Bernick''s Duluth', '', '', '4301 W Michigan St, Duluth MN', 'Net 30', '11:00 am on Mondays', 'Bi-weekly', '10-15 tractors, 10-15 trailers, 5-8 box trucks, 6-10 smaller vehicles (~35 total units)', 'Anything with a Bernick''s logo on it can be washed. Parked on all sides of the building; smaller vehicles can be in the employee lot. Drivers sometimes move them mid-wash — get photos of unit numbers early.', 'Group of 2-3 drivers that complain about small things: windshields, mudflaps/tires, tops of trailers', '300 min', '2 in box, 1 in van toward end', '[]'::jsonb, false, 'client'),
    (v_company, 'Bimbo Bakeries Hibbing', '', '', '2119 MN-37, Hibbing MN', 'Net 30', '10:00 am Wednesdays', 'Bi-weekly', '4-7 box trucks', 'N/A', 'N/A', '60 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Bimbo Bakeries Superior', '', '', '1607 N 6th St, Superior WI', 'Net 30', '11:00 am Wednesdays', 'Bi-weekly', '7-10 box trucks', 'TRICKY — REQUIRES TRAINING (notify management if sent untrained). Door code 1425. Key box code 4132E. Pull trucks ALL the way out to wash, then back them in. Lift gates UP before moving. Keep garage doors shut as much as possible (mice + no wash chems in the building).', 'Mostly concerned about safe driving/backing, keeping trucks straight in spots, liftgates up when moving / down when done', '160 min', '1 (2 makes it ~45 min faster)', '[]'::jsonb, true, 'client'),
    (v_company, 'Bix Produce', '', '', '1301 Garfield Ave, Superior WI', 'Net 30', '10:30 am', 'Bi-weekly', '1-2 box trucks', 'Every other wash they want the backs of the box sprayed out too (specified on schedule)', 'Backs not sprayed out well enough (leftover veggies)', '30 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Blade Companies', 'Luke', '', '5257 Caribou Lake Rd, Saginaw MN', 'Net 30', 'Random — Luke specifies', 'Bi-weekly', '1 tractor, 1 dump truck (changes a lot)', 'We do these at his house — owner operator. Sometimes the address takes you past his driveway (call management with issues).', 'Owner operators are always PICKY! Take your time — he pays well (sometimes tips) and is a great guy', '45 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Border States', '', '', '4451 Airpark Blvd, Duluth, MN 55811', 'Net 30', '5:30 pm on Wednesday', 'Bi-weekly', '2 curtainside box trucks, 1 curtainside trailer, 1 tractor, 1 cargo van', 'UNITS PARKED ON LEFT-HAND SIDE OF LOT. DO NOT GO NEAR FENCED AREA ON RIGHT SIDE — WILL SET OFF MOTION SENSORS', '', '', '', '[]'::jsonb, false, 'client'),
    (v_company, 'Carlson Timber', '', '', 'WLSSD Transfer Station', 'Net 30', '', 'Monthly', 'Material handler, loader, 4 tractors (211, 215, 216, 217 — open hood and wash engine bay), 4 trailers', 'Open panels and wash inside on heavy equipment', '', '', '', '[]'::jsonb, false, 'client'),
    (v_company, 'Charter Spectrum', '', '', '640 Garfield Ave, Duluth MN', 'Net 30', 'Wednesdays 8:00 am', 'Monthly', '~20-25 cargo vans and pickups', 'We wash during their monthly meeting so workers are present and moving. Wash everything that says Charter. COLLECT PLATE NUMBERS!!! Stay until 11 — first wave at the 8am meeting, second wave at 10am.', 'N/A', '~180 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'CHS', 'Cenex Guard Shack', '(218) 341-0595', '41 Dock St, Superior, WI', 'Net 30', 'Saturday @ 9am (1 truck leaves at 10am)', 'Biweekly', '2 tractors, 2 tanker trailers', 'Call the Cenex Guard Shack to be let through the gate — they should know you''re coming. Go right once you enter. Mark down unit #s for trucks (fenders) and trailers (front & back).', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Cintas Duluth', '', '', '367 Garfield Ave, Superior WI', 'Net 30', 'Varies — parked Friday 5:00 pm through Sunday', 'Weekly', '8-16 box trucks', 'Tough to squeeze in between; fences make the backs hard (do your best). Wash everything that says Cintas. Sometimes film on the sides needs scrubbing even with 2-step.', 'Backs of trucks, buggy windshields, frozen doors (open/close after washing on really cold days)', '180 min', '1, preferably 2', '[]'::jsonb, false, 'client'),
    (v_company, 'Circle K', '', '', '1325 MN-45, Cloquet, MN 55720', 'Net 30', 'Monday @ 5:30 pm', 'Monthly', '4 tractors, 5 trailers', '', '', '', '2', '[]'::jsonb, false, 'client'),
    (v_company, 'Coca-Cola', '', '', '300 S Central Ave, Duluth MN', 'Net 30', '2:00 pm Fridays (arrive before 3 to get let in the gate)', 'Quarterly', '5-8 tractors, 5-8 trailers, 3-5 box trucks. DO NOT WASH PICKUPS OR VANS. 13 units every 4 months.', 'Sometimes you have to go inside and say ''I am here to wash trucks'' to get let in the gate', 'Showing up too late to beat the gate', '180 min', '2', '[]'::jsonb, false, 'client'),
    (v_company, 'Contract Tile & Carpet', '', '', 'Cintas lot', 'Net 30', 'During Cintas wash', 'Biweekly', '1 box truck', 'They bring the box truck over during the Cintas wash. If they don''t show, go down the street and ask when done with Cintas.', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Country Hearth Bemidji', '', '', '418 Paul Bunyan Dr SE, Bemidji, MN 56601', 'Net 30', 'Saturday at 1:30 pm', 'Bi-weekly', '1 box truck, 2 stepvans', 'They will pull trucks out to hit the backs', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Country Hearth Duluth', '', '', '43 W Central Entrance, Duluth, MN 55811', 'Net 30', '11:00 am on Wednesdays', 'Bi-weekly', '8-10 box trucks', 'Weird back alley to wash in — do NOT block the alley, don''t let people run over your hose. DO NOT WASH TRACTORS AND TRAILERS.', '', '80 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Country Hearth Grand Rapids', '', '', '3210 SE 6th Ave, Grand Rapids, MN 55744', 'Net 30', 'Saturday after 12 pm, or Sunday', 'Bi-weekly', '3 stepvans', '', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Dayton Freight', '', '', '3759 Midway Rd, Hermantown', 'Net 30', 'Weekends, no specific time', 'Bi-weekly', '5-7 tractors, 1-3 box trucks. Only wash trailers pulled away from the dock (skip ones against the dock or tucked in the corner).', '', 'Bugs, windows, mudflaps', '90 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Del Zotto Products', '', '', '1900 Co Rd 1, Wrenshall, MN 55797', 'Net 30', 'Weekends', 'Monthly', '2 tractors, 3 trailers, 2 boom trucks', 'They line up the units they want done directly behind the building', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Demolicious', '', '', '306 S Central Ave, Duluth, MN 55807', 'Net 30', 'Fridays at 3 pm / after Coca-Cola', 'Hook-lifts weekly, tractor monthly', '2 hook-lift trucks, 1 tractor', 'Check in at front desk first. POLISH SAFE ON PETERBILT HOOK-LIFT; REGULAR CHEM ON STERLING HOOK-LIFT & TRACTOR.', '', '', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Dr. Pepper', '', '', '1230 Poplar Ave, Superior, WI', 'Net 30', '9:00 am Sundays', 'Weekly', '5-7 tractors, 5-7 trailers, 4-6 box trucks, 1-2 cars/pickups, 1 dock washout. DO NOT WASH E13036 or B96027.', 'Unit numbers starting with ''M'' are box trucks. ASK MANAGEMENT IF YOU DON''T KNOW WHAT A DOCK WASH IS.', 'Chemical streaking leftover, bugs', '120 min', '1, pref. 2', '[]'::jsonb, false, 'client'),
    (v_company, 'Duluth Tire', '', '', '2802 W Superior St, Duluth, MN 55806', 'Net 30', 'Fridays after Paradis (roughly 4:30)', 'Bi-weekly', '3-4 box trucks, some pickups, rarely a trailer. GO IN AND ASK what they want washed — sometimes nothing.', '', 'Chemical streaking leftover, bugs', '30 min', '1-2', '[]'::jsonb, false, 'client'),
    (v_company, 'Duke Boys Auto', 'Darin', '(218) 391-6097', '6110 Grand Ave, Duluth, MN 55807', 'Net 30', 'Fridays after Demolicious', 'Weekly', '2 Peterbilt tractors, 2 lowboy trailers', 'TAKE BEFORE AND AFTERS TO COVER US. TEXT DARIN 30 MINUTES BEFORE ARRIVAL.', 'VERY PICKY! Complained about mud on tires — wants them scrubbed!', '', '', '[]'::jsonb, false, 'client'),
