    (v_company, 'Estes Express', '', '', '3302 W 3rd St, Duluth', 'Net 30', 'Random on weekends', 'Every 60 days', '8-15 total: 3-6 tractors, 2 box trucks, 5-6 trailer DOORS only', 'They want only the DOORS on their trailers done — just the back doors on ones pulled away from the dock.', 'Always really gross at 60 days but they expect a high-level wash anyway', '80 min', '1, highly pref. 2', '[]'::jsonb, false, 'client'),
    (v_company, 'FedEx Freight', '', '', '3751 Midway Rd, Hermantown MN', 'Net 30', 'Random, usually mornings (lots of units)', 'As needed', '20-30 total: ~10 tractors, ~10 trailers', 'Only wash trailers pulled away from the docks. Locked gate — we have a key, DON''T forget it at the shop. You MUST lock the gate when you leave (they had an absolute freakout over it once).', 'PICKY — will complain about anything they can', '500 min', '2, pref. 3, ideally 4', '[]'::jsonb, false, 'client'),
    (v_company, 'Ferguson Duluth', '', '', '4209 Airpark Boulevard, Duluth, MN 55811', 'Net 30', 'After 5 pm', 'Biweekly', '8 total: 5 curtain-side box trucks, 2 pickups, 1 cargo van', 'Gate lock code: 2844. WATER RECLAIM. A couple vehicles on the left side of the lot don''t get washed — wash the listed ones parked outside the garages. Close and lock the gate if leaving after 5:00 pm.', 'NEW ACCOUNT — DO AN IMMACULATE JOB! PROVE WE ARE THE BEST!', '60 min', '1', '[]'::jsonb, false, 'client'),
