    (v_company, 'Kimmes Oil', '', '', 'See pin on schedule (maps link)', 'Net 30', 'Weekends, time doesn''t matter', '', '3-5 oil tankers', 'Only wash the tankers — no dump trucks or anything else. Gate CODE: 9634. DO NOT FORGET TO PUT KEY BACK AND LOCK GATE. DO NOT WASH K03 or K02.', '', '60 min', '1', '[]'::jsonb, false, 'client'),
    (v_company, 'Kwik Trip', '', '', '1425 Oakes Ave, Superior, WI 54880', 'Net 30', 'Tuesdays MUST arrive by 1:30 pm (DO NOT BE LATE); Wednesdays after 3:00 pm, usually 4', 'Every Tuesday + every other Wednesday', 'Tuesdays: 3-4 tractors + 3-4 tanker trailers (separate unit #s). Wednesdays: ONLY tractors with box trailers attached (NEVER wash box trailers), 6-8 tractors — don''t forget the tractor wheels under the trailers.', 'GATE ACCESS CODE 45059#. DO UNIT PAIR 242077 & 21102 FIRST ON TUESDAYS (Trent will complain if he''s not first and done fast). UNPLUG TRUCKS BEFORE WASH, REPLUG AFTER. Arrive no later than 1:30 Tuesdays — drivers will be waiting.', 'Being even a minute late on Tuesdays; Wednesday drivers are overall picky', 'Tue 80 min / Wed 70 min', '1', '[]'::jsonb, false, 'client'),
