    (v_company, 'Waste Management - Cohasset', '', '', '511 US-2, Cohasset', 'Net 30', '', 'Weekly', '12-18 trucks — mostly garbage trucks, some pickups and a box truck', 'DO NOT WASH HERE WITHOUT PROPER TRAINING. Leave everything exactly as found: same doors locked, same lights on, trucks in same locations. Chalk tires, plug in trucks, main power switches OFF. A driver meets you to pull trucks — PAY HIM $100 at end of wash.', 'Driver of 217457 is very picky! Overall picky fleet. Biggest complaint is frame rails / undercarriage (battery box, DEF tank etc.)', '400 min', '2 washers + 1 driver best; 1 washer + 1 driver fine', '[]'::jsonb, true, 'client'),
